import { useEffect, useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { PointerLockControls } from '@react-three/drei';
import { Vector3 } from 'three';
import { useKeyboard } from '../hooks/useKeyboard';

const SPEED = 5;
const PLAYER_HEIGHT = 1.8;

export default function PlayerController() {
  const { camera } = useThree();
  const movement = useKeyboard();

  const velocity = useRef(new Vector3());
  const forwardVector = useRef(new Vector3());
  const rightVector = useRef(new Vector3());

  useEffect(() => {
    camera.position.set(0, PLAYER_HEIGHT, 0);
  }, [camera]);

  useFrame((state, delta) => {
    // Determine movement direction intensities based on keys
    const moveForward = (movement.forward ? 1 : 0) - (movement.backward ? 1 : 0);
    const moveRight = (movement.right ? 1 : 0) - (movement.left ? 1 : 0);

    // Get camera's exact global forward vector on the XZ plane
    camera.getWorldDirection(forwardVector.current);
    forwardVector.current.y = 0;
    forwardVector.current.normalize();

    // Calculate the right vector perfectly perpendicular to forward
    rightVector.current.crossVectors(forwardVector.current, camera.up).normalize();

    // Reset velocity every frame and add scaled localized directional forces
    velocity.current.set(0, 0, 0);
    velocity.current.addScaledVector(forwardVector.current, moveForward * SPEED * delta);
    velocity.current.addScaledVector(rightVector.current, moveRight * SPEED * delta);

    // Apply movement
    camera.position.add(velocity.current);

    // Hard-lock to the floor height (simulate collision preventing falling)
    camera.position.y = PLAYER_HEIGHT;
  });

  return <PointerLockControls />;
}
